import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.ufzXw1qY.js";const u=JSON.parse('{"title":"Dual Auth Rotators: Antigravity + OpenAI Google","description":"","frontmatter":{},"headers":[],"relativePath":"examples/dual-auth-rotators.md","filePath":"examples/dual-auth-rotators.md"}'),l={name:"examples/dual-auth-rotators.md"};function n(r,e,s,d,c,p){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="dual-auth-rotators-antigravity-openai-google" tabindex="-1">Dual Auth Rotators: Antigravity + OpenAI Google <a class="header-anchor" href="#dual-auth-rotators-antigravity-openai-google" aria-label="Permalink to &quot;Dual Auth Rotators: Antigravity + OpenAI Google&quot;">​</a></h1><p>This page records the final working state of the two separate auth-rotation systems we stabilized:</p><ul><li><code>openAntigravity-auth-rotator</code></li><li><code>openai-google-rotator</code></li></ul><p>The main goal was to stop expensive false-positive Google account rotations while keeping <code>openai/gpt-5.4</code> usable through the OpenAI token pool.</p><h2 id="final-status" tabindex="-1">Final status <a class="header-anchor" href="#final-status" aria-label="Permalink to &quot;Final status&quot;">​</a></h2><ul><li><code>openai/gpt-5.4</code> is working again.</li><li>The OpenAI token pool is healthy again.</li><li>The antigravity daemon should be treated as <strong>off by default</strong> unless explicitly needed.</li><li>Antigravity auto-rotation is now documented as <strong>Claude-only</strong>, never Gemini-only, never generic 429-based.</li></ul><h2 id="architecture-split" tabindex="-1">Architecture split <a class="header-anchor" href="#architecture-split" aria-label="Permalink to &quot;Architecture split&quot;">​</a></h2><p>These systems must stay logically separate.</p><h3 id="_1-antigravity-rotator" tabindex="-1">1. Antigravity rotator <a class="header-anchor" href="#_1-antigravity-rotator" aria-label="Permalink to &quot;1. Antigravity rotator&quot;">​</a></h3><p>Purpose:</p><ul><li>rotate Antigravity Google accounts only when a <strong>real Claude-specific</strong> rate-limit condition happens</li><li>avoid wasting paid Google accounts on unrelated errors</li></ul><p>Required trigger policy:</p><ul><li>allowed: <ul><li><code>rate-limited for claude</code></li><li><code>rate_limited for claude</code></li><li><code>No Antigravity accounts configured</code></li><li><code>No Antigravity accounts available</code></li><li><code>[RateLimit] ... claude</code></li></ul></li><li>forbidden: <ul><li>Gemini quota events</li><li>generic <code>429</code></li><li>generic <code>RATE_LIMIT_EXCEEDED</code></li><li>OpenAI rate-limit errors</li><li>permission-denied errors</li><li>auth side effects</li><li>guardian checks</li><li>token-expiry side effects</li></ul></li></ul><h3 id="_2-openai-google-rotator" tabindex="-1">2. OpenAI Google rotator <a class="header-anchor" href="#_2-openai-google-rotator" aria-label="Permalink to &quot;2. OpenAI Google rotator&quot;">​</a></h3><p>Purpose:</p><ul><li>create fresh OpenAI auth tokens through Google SSO + ChatGPT onboarding + <code>opencode auth login</code></li><li>push the fresh token into the Supabase-backed <code>openai_tokens</code> pool</li><li>feed the OCI gateway so <code>openai/gpt-5.4</code> works again</li></ul><p>Operational rule:</p><ul><li>when debugging this path, run <strong>only</strong> <code>openai-google-rotator</code></li><li>do <strong>not</strong> auto-start or couple the antigravity daemon during OpenAI pool debugging</li></ul><h2 id="root-cause-summary" tabindex="-1">Root cause summary <a class="header-anchor" href="#root-cause-summary" aria-label="Permalink to &quot;Root cause summary&quot;">​</a></h2><h2 id="antigravity-false-positives" tabindex="-1">Antigravity false positives <a class="header-anchor" href="#antigravity-false-positives" aria-label="Permalink to &quot;Antigravity false positives&quot;">​</a></h2><p>The expensive bug came from overly broad rate-limit matching.</p><p>Observed failure mode:</p><ul><li>antigravity debug logs contained many generic quota messages</li><li>watcher logic matched generic <code>429</code> / <code>RATE_LIMIT_EXCEEDED</code></li><li>Gemini or short-reset quota messages incorrectly triggered a paid Google account rotation</li></ul><p>One confirmed false-positive pattern looked like this:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Response Body (429): ... &quot;You have exhausted your capacity on this model. Your quota will reset after 1s.&quot; ... &quot;reason&quot;: &quot;RATE_LIMIT_EXCEEDED&quot;</span></span></code></pre></div><p>That message was <strong>not enough evidence</strong> for a Claude rotation.</p><h2 id="session-crash-behavior" tabindex="-1">Session crash behavior <a class="header-anchor" href="#session-crash-behavior" aria-label="Permalink to &quot;Session crash behavior&quot;">​</a></h2><p>Another issue was that temporary zero-account states caused plugin crashes with messages like:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No Antigravity accounts configured. Run opencode auth login</span></span></code></pre></div><p>That crash behavior created the impression that sessions had to be manually restarted. The safer behavior is to wait/retry instead of crashing immediately.</p><h2 id="openai-google-flow-breakage" tabindex="-1">OpenAI Google flow breakage <a class="header-anchor" href="#openai-google-flow-breakage" aria-label="Permalink to &quot;OpenAI Google flow breakage&quot;">​</a></h2><p>The OpenAI rotator broke after native Chrome dialog handling was replaced with DOM/JS assumptions.</p><p>Important fact:</p><ul><li>the Chrome sign-in / profile confirmation dialogs in this flow are <strong>native OS dialogs</strong></li><li>they are <strong>not</strong> normal DOM elements</li><li>the old AppleScript-based key sequence was the correct mechanism</li></ul><p>The restored working approach uses the native dialog path again, including the historical:</p><ul><li><code>Shift+Cmd+M</code></li><li><code>Tab</code></li><li><code>Enter</code></li></ul><h2 id="implemented-fixes" tabindex="-1">Implemented fixes <a class="header-anchor" href="#implemented-fixes" aria-label="Permalink to &quot;Implemented fixes&quot;">​</a></h2><h2 id="antigravity-safeguards" tabindex="-1">Antigravity safeguards <a class="header-anchor" href="#antigravity-safeguards" aria-label="Permalink to &quot;Antigravity safeguards&quot;">​</a></h2><p>Documented safe behavior for <code>~/.config/openAntigravity-auth-rotator/</code>:</p><ul><li><code>src/watcher.py</code><ul><li>strict Claude-only whitelist matching</li><li>Gemini and generic quota messages ignored</li></ul></li><li><code>main.py</code><ul><li>lock-file protection against duplicate rotations</li><li>safer daemon-loop behavior</li><li>guardian/token-expiry suppression for auto-rotation</li></ul></li><li>cached plugin behavior <ul><li>wait/retry on temporary zero-account state</li><li>avoid crashing active sessions during short-lived pool transitions</li></ul></li></ul><h2 id="openai-pool-recovery" tabindex="-1">OpenAI pool recovery <a class="header-anchor" href="#openai-pool-recovery" aria-label="Permalink to &quot;OpenAI pool recovery&quot;">​</a></h2><p>Documented safe behavior for the canonical auth-rotator surfaces and the OCI gateway components:</p><ul><li>restored AppleScript-based native Chrome dialog handling in <code>fast_runner.py</code></li><li>kept OpenAI debugging independent from antigravity daemon behavior</li><li>updated <code>.env</code> to use the direct Supabase endpoint:</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SUPABASE_URL=&lt;canonical-supabase-url&gt;</span></span></code></pre></div><ul><li>ensured fresh tokens were pushed into <code>openai_tokens</code></li><li>reset stale active tokens when they were known-dead</li><li>restored OCI gateway <code>OPENAI_BASE</code> to:</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;canonical-openai-gateway-base&gt;/v1</span></span></code></pre></div><h2 id="validation-evidence" tabindex="-1">Validation evidence <a class="header-anchor" href="#validation-evidence" aria-label="Permalink to &quot;Validation evidence&quot;">​</a></h2><p>The following outcomes were confirmed during the recovery:</p><ul><li>Claude-only watcher test cases behaved correctly <ul><li>Claude trigger: accepted</li><li><code>No Antigravity accounts</code>: accepted</li><li>Gemini 429: ignored</li><li>generic 429: ignored</li><li>generic <code>RATE_LIMIT_EXCEEDED</code>: ignored</li><li>OpenAI rate-limit message: ignored</li><li>permission-denied message: ignored</li></ul></li><li><code>openai-google-rotator</code> completed an end-to-end success run <ul><li>Google login</li><li>ChatGPT onboarding</li><li><code>opencode auth login</code></li><li>OAuth callback</li><li><code>push_to_pool.py</code></li></ul></li><li>success log ended with:</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ PIPELINE ERFOLGREICH!</span></span></code></pre></div><ul><li>the user later confirmed the final recovered state: <ul><li>GPT model works again</li><li>pool is healthy again</li></ul></li></ul><h2 id="important-operational-rules" tabindex="-1">Important operational rules <a class="header-anchor" href="#important-operational-rules" aria-label="Permalink to &quot;Important operational rules&quot;">​</a></h2><h2 id="do" tabindex="-1">Do <a class="header-anchor" href="#do" aria-label="Permalink to &quot;Do&quot;">​</a></h2><ul><li>keep the antigravity daemon off unless it is explicitly needed</li><li>treat Antigravity rotation as a Claude-specific protection only</li><li>test OpenAI pool recovery independently</li><li>prefer evidence from current logs and pool state over assumptions</li></ul><h2 id="do-not" tabindex="-1">Do not <a class="header-anchor" href="#do-not" aria-label="Permalink to &quot;Do not&quot;">​</a></h2><ul><li>do not rotate paid Google accounts on Gemini-only quota events</li><li>do not treat any generic <code>429</code> as sufficient evidence</li><li>do not merge OpenAI debugging and antigravity daemon testing into one uncontrolled run</li><li>do not replace native Chrome dialog handling with DOM-only automation for this flow</li></ul><h2 id="known-follow-up-note" tabindex="-1">Known follow-up note <a class="header-anchor" href="#known-follow-up-note" aria-label="Permalink to &quot;Known follow-up note&quot;">​</a></h2><p>One separate Antigravity-side error was observed and should be treated as a different class of problem:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Forbidden ... cloudaicompanion.companions.generateChat ... project rising-fact-p41fc</span></span></code></pre></div><p>That is a project/permission issue, not evidence that the antigravity watcher should rotate accounts.</p><h2 id="related-paths" tabindex="-1">Related paths <a class="header-anchor" href="#related-paths" aria-label="Permalink to &quot;Related paths&quot;">​</a></h2><ul><li><code>~/.config/openAntigravity-auth-rotator/main.py</code></li><li><code>~/.config/openAntigravity-auth-rotator/src/watcher.py</code></li><li><code>~/.config/openAntigravity-auth-rotator/src/rotator.py</code></li><li><code>~/.config/openAntigravity-auth-rotator/src/config.py</code></li><li><code>~/.cache/opencode/node_modules/opencode-antigravity-auth/dist/src/plugin.js</code></li><li><code>./fast_runner.py</code></li><li><code>./push_to_pool.py</code></li><li><code>./token_pool.py</code></li><li><code>/opt/llm-gateway/gateway.py</code></li></ul><h2 id="outcome" tabindex="-1">Outcome <a class="header-anchor" href="#outcome" aria-label="Permalink to &quot;Outcome&quot;">​</a></h2><p>The recovery goal for this round is complete:</p><ul><li>prevent wasteful antigravity false positives</li><li>preserve separation between the two rotators</li><li>restore a healthy OpenAI token pool</li><li>restore working <code>openai/gpt-5.4</code></li></ul><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>Bun-Only</strong></td><td>-1.5</td><td><code>bun install</code> / <code>bun run</code> statt npm</td></tr><tr><td><strong>Annahmen-Verbot</strong></td><td>-5.0</td><td>KEINE Diagnose ohne Beweis</td></tr><tr><td><strong>Test-Beweis-Pflicht</strong></td><td>0.0</td><td>KEIN &quot;Done&quot; ohne echten Test-Lauf</td></tr></tbody></table><p>→ <a href="/best-practices/code-quality.html">Alle Mandate</a></p>',69)])])}const g=a(l,[["render",n]]);export{u as __pageData,g as default};
